def get_mapping(category):
    if category == "OBC-NCL": return OBC_MAP
    if category == "EWS": return EWS_MAP
    return OPEN_MAP

def estimate_marks(rank, category):
    mapping = get_mapping(category)
    ranks = sorted(list(mapping.keys()))
    
    if rank <= ranks[0]: return mapping[ranks[0]]
    if rank >= ranks[-1]: return mapping[ranks[-1]]
    
    for i in range(len(ranks)-1):
        if ranks[i] <= rank <= ranks[i+1]:
            r1, r2 = ranks[i], ranks[i+1]
            m1, m2 = mapping[r1], mapping[r2]
            marks = m1 + (m2 - m1) * ((rank - r1) / (r2 - r1))
            return round(marks)
    return 0

def estimate_rank(marks, category):
    """Reverse algorithm: Given marks, what is the expected rank?"""
    mapping = get_mapping(category)
    ranks = sorted(list(mapping.keys()))
    
    if marks >= mapping[ranks[0]]: return ranks[0]
    if marks <= mapping[ranks[-1]]: return ranks[-1]
    
    for i in range(len(ranks)-1):
        r1, r2 = ranks[i], ranks[i+1]
        m1, m2 = mapping[r1], mapping[r2]
        # Marks decrease as rank increases
        if m1 >= marks >= m2:
            if m1 == m2: return r1
            rank = r1 + (r2 - r1) * ((m1 - marks) / (m1 - m2))
            return int(round(rank))
    return ranks[-1]

