INSTITUTES = [
    "Bhubaneswar", "Bombay", "Mandi", "Delhi", "Indore", "Kharagpur",
    "Hyderabad", "Jodhpur", "Kanpur", "Madras", "Gandhinagar", "Patna",
    "Roorkee", "(ISM) Dhanbad", "Ropar", "(BHU) Varanasi", "Guwahati",
    "Bhilai", "Goa", "Palakkad", "Tirupati", "Jammu", "Dharwad"
]

def split_ranks(num_str):
    n = len(num_str)
    mid = n // 2
    for i in range(mid, 0, -1):
        op, cl = num_str[:i], num_str[i:]
        if cl and not cl.startswith('0') and int(op) <= int(cl): return int(op), int(cl)
    for i in range(mid + 1, n):
        op, cl = num_str[:i], num_str[i:]
        if cl and not cl.startswith('0') and int(op) <= int(cl): return int(op), int(cl)
    return int(num_str), int(num_str)

def parse_text_block(raw_text, category_name, search_tag):
    if not raw_text.strip(): return []
    data = []
    text = raw_text.replace(f"{search_tag}Gender-Neutral", "|Gender-Neutral|")
    text = text.replace(f"{search_tag}Female-only (including Supernumerary)", "|Female-only|")
    chunks = text.split("Indian Institute of Technology ")
    
    for chunk in chunks:
        if not chunk.strip() or "Academic Program" in chunk: continue
        parts = chunk.split("|")
        if len(parts) != 3: continue
        
        inst_prog, gender, ranks = parts[0], parts[1], parts[2]
        
        inst_name = ""
        prog_name = ""
        for i_name in INSTITUTES:
            if inst_prog.startswith(i_name):
                inst_name = f"IIT {i_name}"
                prog_name = inst_prog[len(i_name):].strip()
                break
                
        try:
            op_rank, cl_rank = split_ranks(ranks.strip())
            data.append({
                'Institute': inst_name,
                'Program': prog_name,
                'Category': category_name,
                'Gender': gender,
                'Opening': op_rank,
                'Closing': cl_rank,
                'Marks': estimate_marks(cl_rank, category_name)
            })
        except:
            pass
    return data

def load_all_data():
    all_data = []
    all_data.extend(parse_text_block(RAW_OPEN, "OPEN", "AIOPEN"))
    all_data.extend(parse_text_block(RAW_OBC, "OBC-NCL", "AIOBC-NCL"))
    all_data.extend(parse_text_block(RAW_EWS, "EWS", "AIEWS"))
    
    # Generate some dummy data if the strings are empty (for testing the UI)
    if not all_data:
        all_data = [
            {'Institute': 'IIT Bombay', 'Program': 'Computer Science and Engineering', 'Category': 'OPEN', 'Gender': 'Gender-Neutral', 'Opening': 1, 'Closing': 67, 'Marks': 285},
            {'Institute': 'IIT Delhi', 'Program': 'Electrical Engineering', 'Category': 'OBC-NCL', 'Gender': 'Gender-Neutral', 'Opening': 200, 'Closing': 580, 'Marks': 163},
            {'Institute': 'IIT Kanpur', 'Program': 'Aerospace Engineering', 'Category': 'EWS', 'Gender': 'Gender-Neutral', 'Opening': 800, 'Closing': 1200, 'Marks': 120},
            {'Institute': 'IIT Madras', 'Program': 'Mechanical Engineering', 'Category': 'OPEN', 'Gender': 'Female-only', 'Opening': 1500, 'Closing': 3500, 'Marks': 159},
        ]
    return all_data

