class MasterIITApp:
    def __init__(self, root):
        self.root = root
        self.root.title("Master IIT Rank & Marks Targeter - Advanced")
        self.root.geometry("1280x760")
        self.root.configure(bg="#f4f6f9")
        
        # Set a modern theme & custom styles
        style = ttk.Style()
        if "clam" in style.theme_names():
            style.theme_use("clam")
            
        style.configure("TFrame", background="#f4f6f9")
        style.configure("Sidebar.TFrame", background="#ffffff")
        style.configure("TLabel", background="#ffffff", font=("Segoe UI", 10))
        style.configure("Header.TLabel", background="#ffffff", font=("Segoe UI", 16, "bold"), foreground="#1a73e8")
        style.configure("SubHeader.TLabel", background="#ffffff", font=("Segoe UI", 11, "bold"), foreground="#3c4043")
        style.configure("TButton", font=("Segoe UI", 10, "bold"), padding=5)
        style.configure("Action.TButton", background="#1a73e8", foreground="white")
        
        style.configure("Treeview.Heading", font=('Segoe UI', 10, 'bold'), background="#e8eaed", foreground="#3c4043")
        style.configure("Treeview", rowheight=30, font=('Segoe UI', 10), bordercolor="#dadce0")
        
        self.data = load_all_data()
        self._updating_sync = False # Flag to prevent recursive updates between rank/marks
        
        self.setup_layout()
        self.setup_sidebar()
        self.setup_main_content()
        self.populate_table(self.data)
        
    def setup_layout(self):
        # PanedWindow for Sidebar and Main Content
        self.paned_window = ttk.PanedWindow(self.root, orient=tk.HORIZONTAL)
        self.paned_window.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
        
        self.sidebar = ttk.Frame(self.paned_window, style="Sidebar.TFrame", width=320)
        self.main_content = ttk.Frame(self.paned_window)
        
        self.paned_window.add(self.sidebar, weight=0)
        self.paned_window.add(self.main_content, weight=1)

    def setup_sidebar(self):
        # --- Header ---
        ttk.Label(self.sidebar, text="IIT Predictor", style="Header.TLabel").pack(pady=(20, 5), padx=20, anchor='w')
        ttk.Label(self.sidebar, text="JEE Advanced 2026 Engine", font=("Segoe UI", 9), foreground="#5f6368").pack(padx=20, anchor='w', pady=(0, 20))
        
        ttk.Separator(self.sidebar, orient='horizontal').pack(fill='x', padx=20, pady=5)
        
        # --- Your Profile (The Core Predictor) ---
        ttk.Label(self.sidebar, text="Your Profile", style="SubHeader.TLabel").pack(pady=(15, 10), padx=20, anchor='w')
        
        # Category
        ttk.Label(self.sidebar, text="Category:").pack(padx=20, anchor='w')
        self.cat_var = tk.StringVar(value="OPEN")
        self.cat_combo = ttk.Combobox(self.sidebar, textvariable=self.cat_var, values=["All", "OPEN", "OBC-NCL", "EWS"], state="readonly")
        self.cat_combo.pack(fill='x', padx=20, pady=(2, 10))
        self.cat_var.trace_add("write", self.on_category_change)

        # Marks <-> Rank Sync Frame
        sync_frame = tk.Frame(self.sidebar, bg="#ffffff")
        sync_frame.pack(fill='x', padx=20, pady=5)
        
        tk.Label(sync_frame, text="Exp. Marks", bg="#ffffff", font=("Segoe UI", 9)).grid(row=0, column=0, sticky='w')
        tk.Label(sync_frame, text="Exp. Rank", bg="#ffffff", font=("Segoe UI", 9)).grid(row=0, column=1, sticky='w', padx=(10,0))
        
        self.my_marks_var = tk.StringVar()
        self.my_rank_var = tk.StringVar()
        
        marks_entry = ttk.Entry(sync_frame, textvariable=self.my_marks_var, width=12)
        marks_entry.grid(row=1, column=0, pady=2, sticky='ew')
        
        rank_entry = ttk.Entry(sync_frame, textvariable=self.my_rank_var, width=12)
        rank_entry.grid(row=1, column=1, padx=(10,0), pady=2, sticky='ew')
        
        # Bind traces for auto-sync
        self.my_marks_var.trace_add("write", self.sync_marks_to_rank)
        self.my_rank_var.trace_add("write", self.sync_rank_to_marks)
        
        ttk.Separator(self.sidebar, orient='horizontal').pack(fill='x', padx=20, pady=15)
        
        # --- Advanced Filters ---
        ttk.Label(self.sidebar, text="Advanced Filters", style="SubHeader.TLabel").pack(pady=(5, 10), padx=20, anchor='w')
        
        ttk.Label(self.sidebar, text="Gender Pool:").pack(padx=20, anchor='w')
        self.gender_var = tk.StringVar(value="All")
        self.gender_combo = ttk.Combobox(self.sidebar, textvariable=self.gender_var, values=["All", "Gender-Neutral", "Female-only"], state="readonly")
        self.gender_combo.pack(fill='x', padx=20, pady=(2, 10))
        
        ttk.Label(self.sidebar, text="Institute:").pack(padx=20, anchor='w')
        self.inst_var = tk.StringVar(value="All")
        institutes = ["All"] + sorted(list(set(d['Institute'] for d in self.data))) if self.data else ["All"]
        self.inst_combo = ttk.Combobox(self.sidebar, textvariable=self.inst_var, values=institutes, state="readonly")
        self.inst_combo.pack(fill='x', padx=20, pady=(2, 10))

        ttk.Label(self.sidebar, text="Search Branch (e.g. Computer):").pack(padx=20, anchor='w')
        self.search_var = tk.StringVar()
        ttk.Entry(self.sidebar, textvariable=self.search_var).pack(fill='x', padx=20, pady=(2, 15))
        
        # --- Feasibility Toggle ---
        self.safe_only_var = tk.BooleanVar(value=False)
        self.safe_check = ttk.Checkbutton(self.sidebar, text="Show Only Safe Colleges", variable=self.safe_only_var)
        self.safe_check.pack(padx=20, pady=5, anchor='w')
        
        # --- Buttons ---
        btn_frame = tk.Frame(self.sidebar, bg="#ffffff")
        btn_frame.pack(fill='x', padx=20, pady=20)
        
        ttk.Button(btn_frame, text="Predict Colleges", style="Action.TButton", command=self.apply_filter).pack(fill='x', pady=5)
        ttk.Button(btn_frame, text="Reset Engine", command=self.reset_filter).pack(fill='x', pady=5)

    def setup_main_content(self):
        # Top toolbar
        toolbar = ttk.Frame(self.main_content)
        toolbar.pack(fill='x', pady=(0, 10))
        
        self.stat_label = ttk.Label(toolbar, text="Ready to Predict.", font=('Segoe UI', 11, 'bold'), background="#f4f6f9")
        self.stat_label.pack(side='left')
        
        ttk.Button(toolbar, text="Export CSV", command=self.export_csv).pack(side='right')

        # Table Frame
        table_frame = ttk.Frame(self.main_content)
        table_frame.pack(fill='both', expand=True)
        
        cols = ('Institute', 'Program', 'Category', 'Gender', 'Closing Rank', 'Min Marks', 'Status')
        self.tree = ttk.Treeview(table_frame, columns=cols, show='headings')
        
        col_widths = {'Institute': 140, 'Program': 300, 'Category': 80, 'Gender': 110, 'Closing Rank': 100, 'Min Marks': 90, 'Status': 90}
        for c in cols:
            self.tree.heading(c, text=c, command=lambda _c=c: self.sort_column(_c, False))
            self.tree.column(c, width=col_widths[c], anchor='center' if c not in ['Program', 'Institute'] else 'w')
        
        # Tag configuration for visual status
        self.tree.tag_configure('safe', background="#e6f4ea", foreground="#137333")  # Greenish
        self.tree.tag_configure('reach', background="#fce8e6", foreground="#c5221f") # Reddish
        self.tree.tag_configure('default_odd', background="#ffffff")
        self.tree.tag_configure('default_even', background="#f8f9fa")
        
        scrollbar = ttk.Scrollbar(table_frame, orient=tk.VERTICAL, command=self.tree.yview)
        self.tree.configure(yscroll=scrollbar.set)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        self.tree.pack(side=tk.LEFT, fill='both', expand=True)

    # --- Real-Time Sync Logic ---
    def get_active_category(self):
        cat = self.cat_var.get()
        return cat if cat != "All" else "OPEN"

    def on_category_change(self, *args):
        # Trigger resync of rank/marks when category changes
        if self.my_marks_var.get().isdigit():
            self.sync_marks_to_rank()
        elif self.my_rank_var.get().isdigit():
            self.sync_rank_to_marks()

    def sync_marks_to_rank(self, *args):
        if self._updating_sync: return
        val = self.my_marks_var.get()
        if val.isdigit():
            self._updating_sync = True
            rank = estimate_rank(int(val), self.get_active_category())
            self.my_rank_var.set(str(rank))
            self._updating_sync = False
        elif val == "":
            self._updating_sync = True
            self.my_rank_var.set("")
            self._updating_sync = False

    def sync_rank_to_marks(self, *args):
        if self._updating_sync: return
        val = self.my_rank_var.get()
        if val.isdigit():
            self._updating_sync = True
            marks = estimate_marks(int(val), self.get_active_category())
            self.my_marks_var.set(str(marks))
            self._updating_sync = False
        elif val == "":
            self._updating_sync = True
            self.my_marks_var.set("")
            self._updating_sync = False

    # --- Filtering and Processing ---
    def apply_filter(self):
        filtered = self.data
        
        cat = self.cat_var.get()
        if cat != "All": filtered = [d for d in filtered if d['Category'] == cat]
            
        inst = self.inst_var.get()
        if inst != "All": filtered = [d for d in filtered if d['Institute'] == inst]
            
        gender = self.gender_var.get()
        if gender != "All": filtered = [d for d in filtered if d['Gender'] == gender]
        
        keyword = self.search_var.get().lower().strip()
        if keyword: filtered = [d for d in filtered if keyword in d['Program'].lower()]
            
        my_rank = self.my_rank_var.get()
        safe_only = self.safe_only_var.get()
        
        # Apply Feasibility Filter
        if my_rank.isdigit() and safe_only:
            filtered = [d for d in filtered if int(my_rank) <= d['Closing']]
            
        self.populate_table(filtered, my_rank)

    def reset_filter(self):
        self.cat_var.set("OPEN")
        self.inst_var.set("All")
        self.gender_var.set("All")
        self.search_var.set("")
        self.my_rank_var.set("")
        self.my_marks_var.set("")
        self.safe_only_var.set(False)
        self.populate_table(self.data)

    def populate_table(self, data, my_rank_str=""):
        self.tree.delete(*self.tree.get_children())
        if not data:
            self.stat_label.config(text="No matching programs found.")
            return
            
        self.stat_label.config(text=f"Showing {len(data)} Programs")
        
        my_rank = int(my_rank_str) if my_rank_str.isdigit() else None
        
        for index, d in enumerate(data):
            # Determine Status and Colors
            status = "-"
            tag = 'default_even' if index % 2 == 0 else 'default_odd'
            
            if my_rank is not None:
                if my_rank <= d['Closing']:
                    status = "Safe"
                    tag = "safe"
                else:
                    status = "Reach"
                    tag = "reach"

            self.tree.insert('', 'end', values=(
                d['Institute'], 
                d['Program'], 
                d['Category'], 
                d['Gender'], 
                d['Closing'], 
                f"{d['Marks']} marks",
                status
            ), tags=(tag,))

    def sort_column(self, col, reverse):
        l = [(self.tree.set(k, col), k) for k in self.tree.get_children('')]
        if col == 'Closing Rank':
            l.sort(key=lambda t: int(t[0]), reverse=reverse)
        elif col == 'Min Marks':
            l.sort(key=lambda t: int(t[0].split()[0]), reverse=reverse)
        else:
            l.sort(reverse=reverse)
            
        for index, (val, k) in enumerate(l):
            self.tree.move(k, '', index)
            # Re-apply alternating tags if they are default, leave safe/reach colors alone
            current_tags = self.tree.item(k, 'tags')
            if 'safe' not in current_tags and 'reach' not in current_tags:
                tag = 'default_even' if index % 2 == 0 else 'default_odd'
                self.tree.item(k, tags=(tag,))
            
        self.tree.heading(col, command=lambda: self.sort_column(col, not reverse))

    def export_csv(self):
        rows = self.tree.get_children()
        if not rows:
            messagebox.showwarning("No Data", "Filter some data first before exporting!")
            return
            
        filepath = filedialog.asksaveasfilename(defaultextension=".csv", filetypes=[("CSV Files", "*.csv")])
        if not filepath: return
            
        with open(filepath, mode='w', newline='') as file:
            writer = csv.writer(file)
            writer.writerow(['Institute', 'Program', 'Category', 'Gender Pool', 'Closing Rank', 'Min Marks Required', 'Status'])
            for row_id in rows:
                writer.writerow(self.tree.item(row_id)['values'])
        
        messagebox.showinfo("Export Successful", f"Data exported to:\n{filepath}")

if __name__ == "__main__":
    root = tk.Tk()
    app = MasterIITApp(root)
    root.mainloop()